export default "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>TeamManager</title>\n    <style>\n        :root{--font:'Inter',system-ui,-apple-system,sans-serif;--mono:'SF Mono','Cascadia Code','Fira Code',monospace;--bg-0:#f0f4f8;--bg-1:#fff;--bg-2:#f5f7fa;--bg-3:#edf0f5;--bd:#dfe3ea;--t1:#1a2332;--t2:#4a5568;--t3:#8899aa;--acc:#2563eb;--acc-bg:rgba(37,99,235,.06);--acc-bd:rgba(37,99,235,.2);--r:8px;--rl:12px;--sh:0 1px 3px rgba(0,0,0,.06),0 6px 16px rgba(0,0,0,.04);--grn:#16a34a;--grn-bg:#ecfdf5;--grn-bd:#bbf7d0;--red:#dc2626;--red-bg:#fef2f2;--red-bd:#fecaca;--blue-bg:rgba(37,99,235,.08);--blue-bd:rgba(37,99,235,.25)}\n        *{box-sizing:border-box;margin:0;padding:0}\n        body{font-family:var(--font);background:var(--bg-0);color:var(--t1);-webkit-font-smoothing:antialiased}\n        body.no-scroll{overflow:hidden}\n\n        /* SETUP */\n        #setup{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:40px 20px;gap:20px}\n        #setup h1{font-size:28px;font-weight:800;color:var(--t1);letter-spacing:-.02em}\n        #setup h1 .ac{color:var(--acc)}\n        #setup p{color:var(--t3);font-size:14px}\n        .setup-card{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--rl);padding:32px 40px;text-align:center;cursor:pointer;transition:all .2s;box-shadow:0 1px 3px rgba(0,0,0,.04);max-width:360px;width:100%}\n        .setup-card:hover{border-color:var(--acc);box-shadow:0 4px 20px rgba(37,99,235,.1);transform:translateY(-2px)}\n        .setup-err{color:var(--red);font-size:13px;display:none;margin-top:10px}\n\n        /* BUTTONS */\n        .btn{padding:7px 16px;font-family:var(--font);font-size:13px;font-weight:600;border-radius:var(--r);cursor:pointer;border:1px solid var(--bd);background:var(--bg-1);color:var(--t2);transition:all 100ms}\n        .btn:hover{background:var(--bg-2)}\n        .btn-p{background:var(--acc);color:#fff;border-color:var(--acc)}\n        .btn-p:hover{background:#1d4ed8}\n        .btn-sm{padding:4px 10px;font-size:12px}\n        .btn-d{color:var(--red);border-color:var(--red-bd)}\n        .btn-d:hover{background:var(--red-bg)}\n\n        /* APP SHELL */\n        #app{display:none}\n        .toolbar{display:flex;align-items:center;gap:14px;padding:12px 28px;background:var(--bg-1);border-bottom:1px solid var(--bd);position:sticky;top:0;z-index:100}\n        .toolbar h2{font-size:16px;font-weight:800;color:var(--t1);white-space:nowrap}\n        .toolbar h2 .ac{color:var(--acc)}\n        .view-toggle{display:inline-flex;background:var(--bg-3);border-radius:var(--r);padding:3px;gap:2px}\n        .view-toggle-btn{display:inline-flex;align-items:center;gap:5px;padding:6px 14px;font-family:var(--font);font-size:13px;font-weight:600;border:none;border-radius:6px;cursor:pointer;background:transparent;color:var(--t3);transition:all 150ms;white-space:nowrap}\n        .view-toggle-btn:hover{color:var(--t2)}\n        .view-toggle-btn.active{background:var(--bg-1);color:var(--t1);box-shadow:0 1px 3px rgba(0,0,0,.08)}\n        .view-toggle-btn svg{width:14px;height:14px;flex-shrink:0}\n        .file-badges{display:flex;gap:6px;margin-left:auto}\n        .fb{font-size:11px;background:var(--bg-3);color:var(--t3);padding:3px 10px;border-radius:20px;font-weight:600}\n\n        /* SEARCH & FILTERS */\n        .search-wrap{position:relative;flex:1;max-width:320px}\n        .search-wrap svg{position:absolute;left:10px;top:50%;transform:translateY(-50%);width:15px;height:15px;color:var(--t3);pointer-events:none}\n        .search-input{width:100%;padding:8px 30px 8px 32px;font-family:var(--font);font-size:13px;border:1px solid var(--bd);border-radius:var(--r);background:var(--bg-2);color:var(--t1);transition:border-color .15s}\n        .search-input:focus{outline:none;border-color:var(--acc);background:var(--bg-1)}\n        .search-clear{display:none;position:absolute;right:8px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--t3);font-size:16px;cursor:pointer;padding:2px 6px;border-radius:4px}\n        .search-clear:hover{color:var(--t1);background:var(--bg-2)}\n        .search-wrap.has-query .search-clear{display:block}\n        .filter-bar{padding:10px 24px;background:var(--bg-2);border-bottom:1px solid var(--bd)}\n        .filter-bar-row{display:flex;align-items:flex-end;gap:12px;flex-wrap:wrap}\n        .fb-group{display:flex;flex-direction:column;gap:3px}\n        .fb-group label{font-size:11px;font-weight:600;color:var(--t3);text-transform:uppercase;letter-spacing:.04em}\n        .fb-group select,.fb-group input{padding:6px 10px;font-family:var(--font);font-size:13px;background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--r);color:var(--t1);cursor:pointer;min-width:120px}\n\n        /* STATS */\n        .emr-stats{padding:12px 24px;display:flex;gap:20px;border-bottom:1px solid var(--bd);background:var(--bg-1)}\n        .emr-stat{font-size:13px;color:var(--t2)}.emr-stat span{font-weight:700;color:var(--t1)}\n\n        /* EMR CARDS */\n        .emr-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(480px,1fr));gap:14px;padding:20px 24px;max-width:1100px;margin:0 auto}\n        .emr-card{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--rl);overflow:hidden;cursor:pointer;transition:all 150ms;box-shadow:0 1px 3px rgba(0,0,0,.04)}\n        .emr-card:hover{border-color:var(--acc);box-shadow:0 4px 16px rgba(37,99,235,.1);transform:translateY(-1px)}\n        .emr-card.inactive{opacity:.45}\n        .emr-card-head{padding:14px 16px;display:flex;align-items:flex-start;justify-content:space-between;gap:8px}\n        .emr-card-name{font-size:16px;font-weight:700;color:var(--t1);line-height:1.2}\n        .emr-card-id{font-family:var(--mono);font-size:11px;color:var(--t3);margin-top:2px}\n        .emr-card-badge{font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;white-space:nowrap}\n        .emr-card-body{padding:0 16px 12px;display:grid;grid-template-columns:1fr 1fr;gap:8px 16px}\n        .emr-field{display:flex;flex-direction:column;gap:1px}\n        .emr-field-label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3)}\n        .emr-field-val{font-size:13px;color:var(--t1)}\n        .emr-field-val.urgent{color:var(--red);font-weight:700}\n        .emr-card-foot{padding:8px 16px;background:var(--bg-2);border-top:1px solid var(--bd);display:flex;align-items:center;justify-content:space-between}\n        .emr-status{font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px}\n        .emr-status-active{background:var(--grn-bg);color:var(--grn);border:1px solid var(--grn-bd)}\n        .emr-status-inactive{background:var(--red-bg);color:var(--red);border:1px solid var(--red-bd)}\n        .emr-notes-count{font-size:12px;color:var(--t3)}\n        .emr-empty{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:60px;color:var(--t3)}\n\n        /* MODALS */\n        .mo{position:fixed;inset:0;background:rgba(26,35,50,.45);backdrop-filter:blur(4px);display:flex;align-items:center;justify-content:center;z-index:500;opacity:0;pointer-events:none;transition:opacity .15s}\n        .mo.open{opacity:1;pointer-events:auto}\n        .modal{background:var(--bg-1);border-radius:var(--rl);box-shadow:0 20px 60px rgba(0,0,0,.15);width:calc(100% - 40px);overflow:hidden;animation:modalIn .15s}\n        @keyframes modalIn{from{transform:translateY(10px);opacity:0}to{transform:none;opacity:1}}\n        .modal-sm{max-width:420px}\n        .mh{display:flex;align-items:center;justify-content:space-between;padding:16px 20px;border-bottom:1px solid var(--bd)}\n        .mh h2{font-size:16px;font-weight:700;color:var(--t1)}\n        .mh h2 .sub{font-weight:400;color:var(--t3);font-size:13px}\n        .mx{background:none;border:none;font-size:22px;color:var(--t3);cursor:pointer;padding:0 4px;line-height:1}\n        .mx:hover{color:var(--t1)}\n        .mb{padding:20px}\n        .mf{display:flex;justify-content:flex-end;gap:8px;padding:14px 20px;border-top:1px solid var(--bd);background:var(--bg-2)}\n        .fg{display:flex;flex-direction:column;gap:12px}\n        .fi{display:flex;flex-direction:column;gap:4px}\n        .fi label{font-size:11px;font-weight:650;color:var(--t3);text-transform:uppercase;letter-spacing:.05em}\n        .fi input,.fi select,.fi textarea{padding:8px 12px;font-family:var(--font);font-size:14px;border:1px solid var(--bd);border-radius:var(--r);background:var(--bg-1);color:var(--t1)}\n        .fi input:focus,.fi select:focus,.fi textarea:focus{outline:none;border-color:var(--acc)}\n\n        /* PATIENT HEADER */\n        .patient-header{padding:20px;background:linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%);color:#fff}\n        .ph-name{font-size:22px;font-weight:800;margin-bottom:8px;letter-spacing:-.01em}\n        .ph-details{display:flex;flex-wrap:wrap;gap:6px 18px}\n        .ph-item{display:flex;align-items:center;gap:5px;font-size:12px}\n        .ph-label{color:rgba(255,255,255,.6);font-weight:700;text-transform:uppercase;letter-spacing:.04em;font-size:10px}\n        .ph-val{color:#fff;font-family:var(--mono);font-size:12px}\n        .copy-btn{background:none;border:none;cursor:pointer;color:rgba(255,255,255,.5);font-size:13px;padding:1px 3px}\n        .copy-btn:hover{color:#fff}\n        .note-info{padding:0;border-bottom:1px solid var(--bd);flex-shrink:0}\n\n        /* NOTES MODAL */\n        .notes-modal-wrap{display:flex;align-items:flex-start;gap:16px;max-height:90vh}\n        .modal-notes{max-width:900px;width:900px;height:80vh;max-height:720px;display:flex;flex-direction:column;overflow:hidden}\n        .modal-notes .mh{flex-shrink:0}\n        .note-fields{display:flex;gap:12px;padding:12px 20px;border-bottom:1px solid var(--bd);flex-shrink:0;flex-wrap:wrap}\n        .nf-group{display:flex;flex-direction:column;gap:3px}\n        .nf-group label{font-size:10px;font-weight:700;color:var(--t3);text-transform:uppercase;letter-spacing:.04em}\n        .nf-group input,.nf-group select{padding:5px 8px;font-family:var(--font);font-size:12px;border:1px solid var(--bd);border-radius:var(--r);background:var(--bg-1);color:var(--t1)}\n        .notes-body{flex:1;display:flex;overflow:hidden}\n        .notes-left{width:320px;flex-shrink:0;display:flex;flex-direction:column;border-right:1px solid var(--bd);padding:20px;gap:12px;background:var(--bg-2)}\n        .notes-left label{font-size:11px;font-weight:650;color:var(--t3);text-transform:uppercase;letter-spacing:.05em}\n        .notes-ta{flex:1;padding:10px 12px;font-family:var(--font);font-size:13px;border:1px solid var(--bd);border-radius:var(--r);resize:none;min-height:120px;color:var(--t1);background:var(--bg-1)}\n        .notes-ta:focus{outline:none;border-color:var(--acc)}\n        .notes-right{flex:1;overflow-y:auto}\n        .notes-right-header{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);padding:16px 20px;border-bottom:1px solid var(--bd);background:var(--bg-2);position:sticky;top:0;z-index:1}\n        .notes-list{padding:12px}\n        .notes-empty{text-align:center;padding:40px 20px;color:var(--t3);font-size:13px}\n        .note-card{border:1px solid var(--bd);border-radius:var(--r);margin-bottom:8px;overflow:hidden;transition:border-color .15s}\n        .note-card:hover{border-color:var(--acc-bd)}\n        .note-head{display:flex;align-items:center;justify-content:space-between;padding:8px 12px;background:var(--bg-2);font-size:12px;color:var(--t3);border-bottom:1px solid var(--bd)}\n        .note-text-wrap{padding:10px 12px}\n        .note-text{font-size:13px;color:var(--t1);line-height:1.5;white-space:pre-wrap}\n        .note-edit,.note-del{background:none;border:none;cursor:pointer;font-size:14px;color:var(--t3);padding:2px 4px}\n        .note-edit:hover{color:var(--acc)}.note-del:hover{color:var(--red)}\n\n        /* CALENDAR */\n        .calendar-view{display:none;padding:20px 24px}\n        .calendar-view.visible{display:block}\n        .cal-container{background:var(--bg-1);border:1px solid var(--bd);border-radius:var(--rl);overflow:hidden;box-shadow:var(--sh)}\n        .cal-header{display:flex;align-items:center;justify-content:space-between;padding:16px 20px;border-bottom:1px solid var(--bd)}\n        .cal-month-title{font-size:18px;font-weight:700;color:var(--t1)}\n        .cal-nav{display:flex;gap:6px}\n        .cal-nav-btn{width:32px;height:32px;border-radius:var(--r);border:1px solid var(--bd);background:var(--bg-1);cursor:pointer;font-size:16px;color:var(--t2);display:flex;align-items:center;justify-content:center;transition:all .1s}\n        .cal-nav-btn:hover{background:var(--bg-2);border-color:var(--acc)}\n        .cal-today-btn{padding:6px 14px;border-radius:var(--r);border:1px solid var(--bd);background:var(--bg-1);cursor:pointer;font-family:var(--font);font-size:12px;font-weight:600;color:var(--acc);transition:all .1s}\n        .cal-today-btn:hover{background:var(--blue-bg);border-color:var(--acc-bd)}\n        .cal-grid{display:grid;grid-template-columns:repeat(7,1fr)}\n        .cal-day-header{padding:10px;text-align:center;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--t3);background:var(--bg-2);border-bottom:1px solid var(--bd)}\n        .cal-day{position:relative;min-height:100px;padding:8px;border-bottom:1px solid #f0f1f4;border-right:1px solid #f0f1f4;cursor:pointer;transition:background 120ms;background:var(--bg-1)}\n        .cal-day:hover{background:var(--bg-2)}\n        .cal-day.outside{background:var(--bg-2);opacity:.4;cursor:default}\n        .cal-day.today{background:var(--blue-bg)}\n        .cal-day.selected{background:var(--acc-bg);box-shadow:inset 0 0 0 2px var(--acc)}\n        .cal-day-num{font-size:13px;font-weight:600;color:var(--t1);margin-bottom:4px}\n        .cal-day-badge{display:inline-block;font-size:10px;font-weight:700;padding:1px 6px;border-radius:10px;margin-bottom:3px}\n        .cal-day-badge.normal{background:var(--blue-bg);color:var(--acc);border:1px solid var(--blue-bd)}\n        .cal-day-badge.urgent{background:var(--red-bg);color:var(--red);border:1px solid var(--red-bd)}\n        .cal-preview{font-size:10px;color:var(--t2);line-height:1.3;padding:1px 0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n        .cal-preview span{color:var(--t3);font-size:9px}\n        .cal-preview-more{font-size:10px;color:var(--acc);font-weight:600;margin-top:1px}\n\n        /* CALENDAR DAY MODAL */\n        .cal-day-modal{max-width:580px;height:600px;display:flex;flex-direction:column;overflow:hidden}\n        .cal-day-cards{flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:10px}\n        .cal-day-card{background:var(--bg-2);border:1px solid var(--bd);border-radius:var(--rl);padding:14px 16px;cursor:pointer;transition:all 120ms;border-left:3px solid transparent}\n        .cal-day-card:hover{border-left-color:var(--acc);box-shadow:0 2px 8px rgba(0,0,0,.06)}\n        .cal-day-card-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:6px}\n        .cal-day-card-name{font-size:15px;font-weight:600;color:var(--t1)}\n        .cal-day-card-id{font-family:var(--mono);font-size:11px;color:var(--t3)}\n        .cal-day-card-row{display:flex;align-items:center;gap:10px;flex-wrap:wrap;font-size:12px;color:var(--t2)}\n\n        /* TOAST */\n        #toasts{position:fixed;bottom:20px;right:20px;z-index:9999;display:flex;flex-direction:column;gap:8px}\n        .toast{padding:10px 18px;border-radius:var(--r);font-size:13px;font-weight:600;box-shadow:0 4px 12px rgba(0,0,0,.15);animation:toastIn .2s;transition:opacity .2s}\n        .toast-success{background:#065f46;color:#ecfdf5}\n        .toast-danger{background:#991b1b;color:#fef2f2}\n        .toast-info{background:#1e40af;color:#eff6ff}\n        .toast.out{opacity:0}\n        @keyframes toastIn{from{transform:translateY(8px);opacity:0}to{transform:none;opacity:1}}\n\n        /* MAPPING PANEL */\n        .map-panel{padding:24px;max-width:600px;margin:0 auto}\n        .map-panel h3{font-size:18px;font-weight:700;color:var(--t1);margin-bottom:16px}\n    </style>\n</head>\n<body>\n\n<!-- SETUP -->\n<div id=\"setup\">\n    <h1>Team<span class=\"ac\">Manager</span></h1>\n    <p>Open your shared Excel file to get started</p>\n    <div class=\"setup-card\" onclick=\"App.openExcelFile()\">\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"var(--acc)\" stroke-width=\"1.5\" style=\"width:40px;height:40px;margin-bottom:12px\"><rect x=\"3\" y=\"3\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M8 7h3l2 5-2 5H8\"/><path d=\"M16 7h-3l-2 5 2 5h3\"/></svg>\n        <div style=\"font-size:16px;font-weight:700;color:var(--t1);margin-bottom:6px\">Open Excel File</div>\n        <p style=\"font-size:12px;color:var(--t3);margin:0\">Select your shared .xlsx workbook</p>\n    </div>\n    <div class=\"setup-err\" id=\"setupErr\"></div>\n</div>\n\n<!-- APP -->\n<div id=\"app\">\n    <div class=\"toolbar\">\n        <h2>Team<span class=\"ac\">Manager</span></h2>\n        <div class=\"view-toggle\">\n            <button class=\"view-toggle-btn active\" data-view=\"table\" onclick=\"App.setView('table')\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1\"/></svg>\n                Cards\n            </button>\n            <button class=\"view-toggle-btn\" data-view=\"calendar\" onclick=\"App.setView('calendar')\">\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\"/><line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\"/><line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\"/></svg>\n                Calendar\n            </button>\n        </div>\n        <div class=\"search-wrap\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><line x1=\"21\" y1=\"21\" x2=\"16.65\" y2=\"16.65\"/></svg>\n            <input type=\"text\" class=\"search-input\" id=\"searchInput\" placeholder=\"Search members...\" oninput=\"App.onSearch(this.value)\" style=\"padding-right:30px\">\n            <button class=\"search-clear\" onclick=\"App.clearSearch()\">&times;</button>\n        </div>\n        <div class=\"file-badges\"><span class=\"fb\" id=\"badgeFile\"></span></div>\n        <button class=\"btn btn-sm\" onclick=\"App.refreshExcel()\">Refresh</button>\n        <button class=\"btn btn-sm\" onclick=\"App.showMapping()\">Remap</button>\n    </div>\n\n    <div class=\"filter-bar\" id=\"filterBar\">\n        <div class=\"filter-bar-row\">\n            <div class=\"fb-group\"><label>CM</label><select id=\"filterCM\" onchange=\"App.render()\"><option value=\"\">All</option></select></div>\n            <div class=\"fb-group\"><label>Call Type</label><select id=\"filterCT\" onchange=\"App.render()\"><option value=\"\">All</option></select></div>\n            <div class=\"fb-group\"><label>SNP</label><select id=\"filterSNP\" onchange=\"App.render()\"><option value=\"\">All</option></select></div>\n            <div class=\"fb-group\"><label>PCP</label><select id=\"filterPCP\" onchange=\"App.render()\"><option value=\"\">All</option></select></div>\n            <div class=\"fb-group\"><label>D/C From</label><input type=\"date\" id=\"filterFrom\" onchange=\"App.render()\"></div>\n            <div class=\"fb-group\"><label>D/C To</label><input type=\"date\" id=\"filterTo\" onchange=\"App.render()\"></div>\n            <button class=\"btn btn-sm\" onclick=\"App.clearFilters()\">Clear</button>\n        </div>\n    </div>\n\n    <!-- CARD VIEW -->\n    <div id=\"cardView\">\n        <div class=\"emr-stats\" id=\"emrStats\"></div>\n        <div class=\"emr-grid\" id=\"emrGrid\"></div>\n        <div class=\"emr-empty\" id=\"emrEmpty\" style=\"display:none\"><p>No members match your filters.</p></div>\n    </div>\n\n    <!-- MAPPING PANEL -->\n    <div id=\"mapPanel\" style=\"display:none\">\n        <div class=\"map-panel\">\n            <h3>Map Excel Columns</h3>\n            <div class=\"fg\" style=\"margin-bottom:14px\">\n                <div class=\"fi\"><label>Members Sheet</label><select id=\"xlSheet\" onchange=\"App.sheetChanged()\"></select></div>\n            </div>\n            <div id=\"xlMappings\" class=\"fg\" style=\"margin-bottom:14px\"></div>\n            <div class=\"fg\" style=\"margin-bottom:14px\">\n                <div class=\"fi\"><label>Notes Sheet</label><select id=\"xlNoteSheet\"></select></div>\n            </div>\n            <p style=\"font-size:12px;color:var(--t3);margin-bottom:16px\">Notes will be stored as: Member ID, Timestamp, Note</p>\n            <button class=\"btn btn-p\" onclick=\"App.applyMapping()\">Load Members</button>\n        </div>\n    </div>\n\n    <!-- CALENDAR VIEW -->\n    <div class=\"calendar-view\" id=\"calendarView\">\n        <div class=\"cal-container\">\n            <div class=\"cal-header\">\n                <div class=\"cal-nav\">\n                    <button class=\"cal-nav-btn\" onclick=\"App.calPrev()\">&lsaquo;</button>\n                    <button class=\"cal-nav-btn\" onclick=\"App.calNext()\">&rsaquo;</button>\n                </div>\n                <div class=\"cal-month-title\" id=\"calTitle\"></div>\n                <button class=\"cal-today-btn\" onclick=\"App.calToday()\">Today</button>\n            </div>\n            <div class=\"cal-grid\" id=\"calGrid\"></div>\n        </div>\n    </div>\n</div>\n\n<!-- NOTES MODAL -->\n<div class=\"mo\" id=\"notesModal\" onclick=\"if(event.target===this)App.hideNotes()\">\n    <div class=\"notes-modal-wrap\">\n        <div class=\"modal modal-notes\">\n            <div class=\"mh\"><h2>Notes<span class=\"sub\" id=\"notesSub\"></span></h2><button class=\"mx\" onclick=\"App.hideNotes()\">&times;</button></div>\n            <div class=\"note-info\" id=\"noteInfo\"></div>\n            <div class=\"note-fields\" id=\"noteFields\"></div>\n            <div class=\"notes-body\">\n                <div class=\"notes-left\">\n                    <label>New Note</label>\n                    <textarea class=\"notes-ta\" id=\"noteInput\" placeholder=\"Type a note...\"></textarea>\n                    <button class=\"btn btn-p\" style=\"align-self:center\" id=\"noteBtn\" onclick=\"App.saveNote()\">Add Note</button>\n                </div>\n                <div class=\"notes-right\">\n                    <div class=\"notes-right-header\">Note History</div>\n                    <div class=\"notes-list\" id=\"notesList\"></div>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<!-- CALENDAR DAY MODAL -->\n<div class=\"mo\" id=\"calDayModal\" onclick=\"if(event.target===this)App.hideCalDay()\">\n    <div class=\"modal cal-day-modal\">\n        <div class=\"mh\"><h2 id=\"calDayTitle\"></h2><button class=\"mx\" onclick=\"App.hideCalDay()\">&times;</button></div>\n        <div id=\"calDayList\" class=\"cal-day-cards\"></div>\n    </div>\n</div>\n\n<div id=\"toasts\"></div>\n\n<script src=\"https://cdn.sheetjs.com/xlsx-0.20.3/package/dist/xlsx.full.min.js\"></script>\n<script>\nvar CALL_TYPES=['Urgent','TOC x1','TOC x2','TOC x3','TOC F/U','ICP x1','ICP x2','ICP x3','HRA x1','HRA x2','HRA x3','ICP HRA'];\nvar CP={};CALL_TYPES.forEach(function(t,i){CP[t]=i});\n\nvar App={\n    handle:null,wb:null,members:[],notes:[],nextNid:1,query:'',\n    calYear:new Date().getFullYear(),calMonth:new Date().getMonth(),calSelectedDate:null,\n    currentView:'table',notesForId:null,editingNoteId:null,_returnToCalDay:false,\n\n    mapFields:[\n        {key:'memberId',label:'Member ID',hints:['member id','memberid','id','hicn']},\n        {key:'lastName',label:'Last Name',hints:['last name','lastname','last']},\n        {key:'firstName',label:'First Name',hints:['first name','firstname','first']},\n        {key:'snpFlag',label:'SNP Flag',hints:['snp flag','snp','flag']},\n        {key:'pcp',label:'PCP',hints:['pcp','primary care','physician']},\n        {key:'dob',label:'DOB',hints:['dob','date of birth','birth']},\n        {key:'callType',label:'Call Type',hints:['call type','calltype','status']},\n        {key:'cm',label:'CM',hints:['cm','care manager','case manager']},\n        {key:'admitDate',label:'Admit Date',hints:['admit date','admit','admission']},\n        {key:'dcDate',label:'D/C Date',hints:['d/c date','dc date','discharge']},\n        {key:'tocApptDate',label:'TOC Appt Date',hints:['toc appt','appointment','toc date']}\n    ],\n\n    getMap:function(){try{return JSON.parse(localStorage.getItem('tmColMap')||'{}')}catch(e){return{}}},\n    saveMap:function(m){localStorage.setItem('tmColMap',JSON.stringify(m))},\n\n    openExcelFile:function(){\n        var self=this;\n        window.showOpenFilePicker({types:[{description:'Excel',accept:{'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet':['.xlsx','.xls']}}]}).then(function(h){\n            self.handle=h[0];return self.handle.getFile();\n        }).then(function(file){\n            self.fileName=file.name;return file.arrayBuffer();\n        }).then(function(buf){\n            self.wb=XLSX.read(buf);\n            document.getElementById('setup').style.display='none';\n            document.getElementById('app').style.display='block';\n            document.getElementById('badgeFile').textContent=self.fileName;\n            var saved=self.getMap();\n            if(saved.sheet!=null){self.applyMapping();return}\n            self.showMapping();\n        }).catch(function(e){if(e.name!=='AbortError')self.toast(e.message,'danger')});\n    },\n\n    refreshExcel:function(){\n        if(!this.handle)return;var self=this;\n        this.handle.getFile().then(function(f){return f.arrayBuffer()}).then(function(buf){\n            self.wb=XLSX.read(buf);self.loadData();self.toast('Refreshed','success');\n        });\n    },\n\n    showMapping:function(){\n        document.getElementById('cardView').style.display='none';\n        document.getElementById('calendarView').classList.remove('visible');\n        document.getElementById('filterBar').style.display='none';\n        document.getElementById('mapPanel').style.display='';\n        var names=this.wb.SheetNames,saved=this.getMap(),self=this;\n        var sSel=document.getElementById('xlSheet');\n        sSel.innerHTML=names.map(function(n,i){return '<option value=\"'+i+'\"'+(saved.sheet===i?' selected':'')+'>'+n+'</option>'}).join('');\n        var nSel=document.getElementById('xlNoteSheet');\n        nSel.innerHTML='<option value=\"__new__\">+ Create \"Notes\" sheet</option>'+names.map(function(n,i){\n            return '<option value=\"'+i+'\"'+((saved.noteSheet===i||(n.toLowerCase()==='notes'&&saved.noteSheet==null))?' selected':'')+'>'+n+'</option>';\n        }).join('');\n        this.sheetChanged();\n    },\n\n    sheetChanged:function(){\n        var si=parseInt(document.getElementById('xlSheet').value);\n        var ws=this.wb.Sheets[this.wb.SheetNames[si]];\n        var data=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});\n        var cols=data[0]?data[0].map(function(h){return String(h).trim()}):[];\n        var saved=this.getMap(),self=this;\n        var html=this.mapFields.map(function(f){\n            var best=-1;\n            if(saved.cols&&saved.cols[f.key]!=null)best=saved.cols[f.key];\n            else cols.forEach(function(c,i){var cl=c.toLowerCase();if(best===-1&&f.hints.some(function(h){return cl.indexOf(h)>-1}))best=i});\n            var opts='<option value=\"-1\">-- Skip --</option>'+cols.map(function(c,i){return '<option value=\"'+i+'\"'+(i===best?' selected':'')+'>'+self.esc(c)+'</option>'}).join('');\n            return '<div class=\"fi\"><label>'+f.label+'</label><select id=\"xlM_'+f.key+'\">'+opts+'</select></div>';\n        }).join('');\n        document.getElementById('xlMappings').innerHTML=html;\n    },\n\n    applyMapping:function(){\n        var saved=this.getMap(),map={};\n        var panel=document.getElementById('mapPanel');\n        if(panel.style.display!=='none'){\n            map.sheet=parseInt(document.getElementById('xlSheet').value);\n            var nv=document.getElementById('xlNoteSheet').value;\n            map.noteSheet=nv==='__new__'?-1:parseInt(nv);\n            map.cols={};var self=this;\n            this.mapFields.forEach(function(f){map.cols[f.key]=parseInt(document.getElementById('xlM_'+f.key).value)});\n            this.saveMap(map);\n        }else{map=saved}\n        this.map=map;\n        // Ensure notes sheet\n        if(map.noteSheet===-1||map.noteSheet==null){\n            var ni=this.wb.SheetNames.indexOf('Notes');\n            if(ni===-1){XLSX.utils.book_append_sheet(this.wb,XLSX.utils.aoa_to_sheet([['Member ID','Timestamp','Note']]),'Notes');map.noteSheet=this.wb.SheetNames.indexOf('Notes');this.saveMap(map);this.saveFile()}\n            else{map.noteSheet=ni;this.saveMap(map)}\n        }\n        panel.style.display='none';\n        document.getElementById('filterBar').style.display='';\n        document.getElementById('cardView').style.display='';\n        this.loadData();\n    },\n\n    loadData:function(){\n        var map=this.map||this.getMap();\n        if(!this.wb||map.sheet==null)return;\n        var ws=this.wb.Sheets[this.wb.SheetNames[map.sheet]];\n        var rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});\n        var c=map.cols,self=this;\n        this.members=[];\n        rows.slice(1).forEach(function(r,ri){\n            var mid=c.memberId>=0?String(r[c.memberId]||'').trim():'';\n            if(!mid)return;\n            var last=c.lastName>=0?String(r[c.lastName]||'').trim():'';\n            var first=c.firstName>=0?String(r[c.firstName]||'').trim():'';\n            var name=last&&first?last+', '+first:(last||first);\n            self.members.push({\n                id:String(ri+1),memberId:mid,name:name,firstName:first,lastName:last,\n                snpFlag:c.snpFlag>=0?String(r[c.snpFlag]||'').trim():'',\n                pcp:c.pcp>=0?String(r[c.pcp]||'').trim():'',\n                dob:c.dob>=0?self.parseDate(r[c.dob]):'',\n                callType:c.callType>=0?String(r[c.callType]||'').trim():'',\n                cm:c.cm>=0?String(r[c.cm]||'').trim():'',\n                admitDate:c.admitDate>=0?self.parseDate(r[c.admitDate]):'',\n                dcDate:c.dcDate>=0?self.parseDate(r[c.dcDate]):'',\n                tocApptDate:c.tocApptDate>=0?self.parseDate(r[c.tocApptDate]):'',\n                nextCall:c.dcDate>=0?self.parseDate(r[c.dcDate]):'',\n                active:true,xlRow:ri+1\n            });\n        });\n        // Notes\n        this.notes=[];\n        if(map.noteSheet>=0){\n            var nws=this.wb.Sheets[this.wb.SheetNames[map.noteSheet]];\n            if(nws){var nr=XLSX.utils.sheet_to_json(nws,{header:1,defval:''});\n                nr.slice(1).forEach(function(r,i){var mid=String(r[0]||'').trim(),ts=String(r[1]||'').trim(),n=String(r[2]||'').trim();if(mid&&n)self.notes.push({id:String(i+1),memberId:mid,ts:ts,note:n})});\n                var mx=0;self.notes.forEach(function(n){var v=parseInt(n.id);if(!isNaN(v)&&v>mx)mx=v});self.nextNid=mx+1;\n            }\n        }\n        this.populateFilters();this.render();\n    },\n\n    parseDate:function(v){\n        if(!v)return'';\n        if(typeof v==='number'){var d=new Date((v-25569)*86400000);return d.toISOString().split('T')[0]}\n        var s=String(v).trim();\n        if(/^\\d{4}-\\d{2}-\\d{2}/.test(s))return s.substring(0,10);\n        var d=new Date(s);return isNaN(d)?s:d.toISOString().split('T')[0];\n    },\n\n    saveFile:function(){\n        if(!this.handle||!this.wb)return;\n        var buf=XLSX.write(this.wb,{bookType:'xlsx',type:'array'});\n        this.handle.createWritable().then(function(w){w.write(new Blob([buf])).then(function(){w.close()})});\n    },\n\n    writeNotes:function(){\n        var map=this.map||this.getMap();if(map.noteSheet<0||!this.wb)return;\n        var aoa=[['Member ID','Timestamp','Note']];\n        this.notes.forEach(function(n){aoa.push([n.memberId,n.ts,n.note])});\n        this.wb.Sheets[this.wb.SheetNames[map.noteSheet]]=XLSX.utils.aoa_to_sheet(aoa);\n        this.saveFile();\n    },\n\n    writeMembers:function(){\n        var map=this.map||this.getMap();if(!this.wb)return;\n        var ws=this.wb.Sheets[this.wb.SheetNames[map.sheet]];var c=map.cols;\n        this.members.forEach(function(m){\n            if(!m.xlRow)return;var r=m.xlRow;\n            var set=function(col,val){if(col>=0){var a=XLSX.utils.encode_cell({r:r,c:col});if(!ws[a])ws[a]={};ws[a].t='s';ws[a].v=val||''}};\n            set(c.callType,m.callType);set(c.cm,m.cm);set(c.admitDate,m.admitDate);set(c.dcDate,m.dcDate);set(c.tocApptDate,m.tocApptDate);\n        });\n        this.saveFile();\n    },\n\n    // FILTERS\n    populateFilters:function(){\n        var cms={},cts={},snps={},pcps={};\n        this.members.forEach(function(m){\n            if(m.cm)cms[m.cm]=true;if(m.callType)cts[m.callType]=true;\n            if(m.snpFlag)snps[m.snpFlag]=true;if(m.pcp)pcps[m.pcp]=true;\n        });\n        var fill=function(id,vals){var el=document.getElementById(id);var v=el.value;el.innerHTML='<option value=\"\">All</option>'+Object.keys(vals).sort().map(function(k){return '<option'+(k===v?' selected':'')+'>'+k+'</option>'}).join('')};\n        fill('filterCM',cms);fill('filterCT',cts);fill('filterSNP',snps);fill('filterPCP',pcps);\n    },\n    clearFilters:function(){\n        ['filterCM','filterCT','filterSNP','filterPCP'].forEach(function(id){document.getElementById(id).value=''});\n        document.getElementById('filterFrom').value='';document.getElementById('filterTo').value='';\n        this.render();\n    },\n    filtered:function(){\n        var list=this.members.slice();\n        var cm=document.getElementById('filterCM').value;\n        var ct=document.getElementById('filterCT').value;\n        var snp=document.getElementById('filterSNP').value;\n        var pcp=document.getElementById('filterPCP').value;\n        var df=document.getElementById('filterFrom').value;\n        var dt=document.getElementById('filterTo').value;\n        if(cm)list=list.filter(function(m){return m.cm===cm});\n        if(ct)list=list.filter(function(m){return m.callType===ct});\n        if(snp)list=list.filter(function(m){return m.snpFlag===snp});\n        if(pcp)list=list.filter(function(m){return m.pcp===pcp});\n        if(df)list=list.filter(function(m){return(m.dcDate||'')>=df});\n        if(dt)list=list.filter(function(m){return(m.dcDate||'')<=dt});\n        if(this.query){var q=this.query.toLowerCase();list=list.filter(function(m){return m.name.toLowerCase().indexOf(q)>-1||(m.memberId||'').toLowerCase().indexOf(q)>-1||(m.cm||'').toLowerCase().indexOf(q)>-1||(m.callType||'').toLowerCase().indexOf(q)>-1||(m.pcp||'').toLowerCase().indexOf(q)>-1})}\n        list.sort(function(a,b){var da=a.dcDate||'9999',db=b.dcDate||'9999';if(da<db)return -1;if(da>db)return 1;var ca=CP[a.callType]!=null?CP[a.callType]:99;var cb=CP[b.callType]!=null?CP[b.callType]:99;return ca-cb});\n        return list;\n    },\n\n    // RENDER\n    render:function(){\n        var list=this.filtered(),self=this;\n        document.getElementById('emrStats').innerHTML='<div class=\"emr-stat\"><span>'+list.length+'</span> of <span>'+this.members.length+'</span> members</div>';\n        if(!list.length){document.getElementById('emrGrid').innerHTML='';document.getElementById('emrEmpty').style.display='';return}\n        document.getElementById('emrEmpty').style.display='none';\n        document.getElementById('emrGrid').innerHTML=list.map(function(m){\n            var nc=self.getNotesFor(m.memberId).length;\n            var isUrg=m.callType==='Urgent';\n            return '<div class=\"emr-card\" onclick=\"App.showNotes(\\''+m.id+'\\')\">'\n                +'<div class=\"emr-card-head\">'\n                +'<div><div class=\"emr-card-name\">'+self.esc(m.name)+'</div><div class=\"emr-card-id\">'+self.esc(m.memberId)+'</div></div>'\n                +(m.snpFlag?'<span class=\"emr-card-badge\" style=\"background:var(--blue-bg);color:var(--acc);border:1px solid var(--blue-bd)\">SNP '+self.esc(m.snpFlag)+'</span>':'')\n                +'</div>'\n                +'<div class=\"emr-card-body\">'\n                +(m.callType?'<div class=\"emr-field\"><div class=\"emr-field-label\">Call Type</div><div class=\"emr-field-val'+(isUrg?' urgent':'')+'\">'+self.esc(m.callType)+'</div></div>':'')\n                +(m.cm?'<div class=\"emr-field\"><div class=\"emr-field-label\">CM</div><div class=\"emr-field-val\">'+self.esc(m.cm)+'</div></div>':'')\n                +(m.admitDate?'<div class=\"emr-field\"><div class=\"emr-field-label\">Admit</div><div class=\"emr-field-val\">'+self.esc(m.admitDate)+'</div></div>':'')\n                +(m.dcDate?'<div class=\"emr-field\"><div class=\"emr-field-label\">D/C Date</div><div class=\"emr-field-val\">'+self.esc(m.dcDate)+'</div></div>':'')\n                +(m.pcp?'<div class=\"emr-field\"><div class=\"emr-field-label\">PCP</div><div class=\"emr-field-val\">'+self.esc(m.pcp)+'</div></div>':'')\n                +(m.tocApptDate?'<div class=\"emr-field\"><div class=\"emr-field-label\">TOC Appt</div><div class=\"emr-field-val\">'+self.esc(m.tocApptDate)+'</div></div>':'')\n                +'</div>'\n                +'<div class=\"emr-card-foot\">'\n                +'<span class=\"emr-notes-count\">'+nc+' note'+(nc!==1?'s':'')+'</span>'\n                +(m.dob?'<span style=\"font-size:11px;color:var(--t3)\">DOB: '+self.esc(m.dob)+'</span>':'')\n                +'</div></div>';\n        }).join('');\n        if(this.currentView==='calendar')this.renderCalendar();\n    },\n\n    // VIEW\n    setView:function(v){\n        this.currentView=v;\n        document.querySelectorAll('.view-toggle-btn').forEach(function(b){b.classList.toggle('active',b.dataset.view===v)});\n        document.getElementById('cardView').style.display=v==='table'?'':'none';\n        document.getElementById('calendarView').classList.toggle('visible',v==='calendar');\n        if(v==='calendar')this.renderCalendar();\n    },\n\n    // SEARCH\n    onSearch:function(v){this.query=v;document.querySelector('.search-wrap').classList.toggle('has-query',!!v);this.render()},\n    clearSearch:function(){document.getElementById('searchInput').value='';this.onSearch('')},\n\n    // NOTES\n    getNotesFor:function(mid){return this.notes.filter(function(n){return n.memberId===mid}).sort(function(a,b){return new Date(b.ts)-new Date(a.ts)})},\n    showNotes:function(id){\n        this.editingNoteId=null;\n        var m=this.members.find(function(x){return x.id===id});if(!m)return;\n        this.notesForId=m.memberId;\n        document.getElementById('notesSub').textContent=' \\u2014 '+m.name;\n        // Patient header\n        var ph='<div class=\"patient-header\">'\n            +'<div class=\"ph-name\">'+this.esc(m.name)+'</div>'\n            +'<div class=\"ph-details\">'\n            +'<div class=\"ph-item\"><span class=\"ph-label\">ID</span><span class=\"ph-val\">'+this.esc(m.memberId)+'</span> <button class=\"copy-btn\" onclick=\"event.stopPropagation();App.copy(\\''+this.esc(m.memberId)+'\\')\">&#9112;</button></div>'\n            +(m.dob?'<div class=\"ph-item\"><span class=\"ph-label\">DOB</span><span class=\"ph-val\">'+this.esc(m.dob)+'</span></div>':'')\n            +(m.pcp?'<div class=\"ph-item\"><span class=\"ph-label\">PCP</span><span class=\"ph-val\">'+this.esc(m.pcp)+'</span></div>':'')\n            +(m.snpFlag?'<div class=\"ph-item\"><span class=\"ph-label\">SNP</span><span class=\"ph-val\">'+this.esc(m.snpFlag)+'</span></div>':'')\n            +(m.cm?'<div class=\"ph-item\"><span class=\"ph-label\">CM</span><span class=\"ph-val\">'+this.esc(m.cm)+'</span></div>':'')\n            +(m.admitDate?'<div class=\"ph-item\"><span class=\"ph-label\">Admit</span><span class=\"ph-val\">'+this.esc(m.admitDate)+'</span></div>':'')\n            +(m.dcDate?'<div class=\"ph-item\"><span class=\"ph-label\">D/C</span><span class=\"ph-val\">'+this.esc(m.dcDate)+'</span></div>':'')\n            +(m.tocApptDate?'<div class=\"ph-item\"><span class=\"ph-label\">TOC Appt</span><span class=\"ph-val\">'+this.esc(m.tocApptDate)+'</span></div>':'')\n            +'</div></div>';\n        document.getElementById('noteInfo').innerHTML=ph;\n        // Editable fields\n        var ctOpts=CALL_TYPES.map(function(t){return '<option'+(t===m.callType?' selected':'')+'>'+t+'</option>'}).join('');\n        document.getElementById('noteFields').innerHTML=\n            '<div class=\"nf-group\"><label>Admit</label><input type=\"date\" id=\"nfAdmit\" value=\"'+(m.admitDate||'')+'\" onchange=\"App.updateFields()\"></div>'\n            +'<div class=\"nf-group\"><label>D/C</label><input type=\"date\" id=\"nfDC\" value=\"'+(m.dcDate||'')+'\" onchange=\"App.updateFields()\"></div>'\n            +'<div class=\"nf-group\"><label>Call Type</label><select id=\"nfCT\" onchange=\"App.updateFields()\"><option value=\"\">Select...</option>'+ctOpts+'</select></div>'\n            +'<div class=\"nf-group\"><label>TOC Appt</label><input type=\"date\" id=\"nfTOC\" value=\"'+(m.tocApptDate||'')+'\" onchange=\"App.updateFields()\"></div>';\n        document.getElementById('noteInput').value='';\n        document.getElementById('noteBtn').textContent='Add Note';\n        this.renderNotesList();\n        document.getElementById('notesModal').classList.add('open');\n        document.body.classList.add('no-scroll');\n        setTimeout(function(){document.getElementById('noteInput').focus()},50);\n    },\n    updateFields:function(){\n        if(!this.notesForId)return;\n        var m=this.members.find(function(x){return x.memberId===App.notesForId});if(!m)return;\n        m.admitDate=document.getElementById('nfAdmit').value;\n        m.dcDate=document.getElementById('nfDC').value;\n        m.nextCall=m.dcDate;\n        m.callType=document.getElementById('nfCT').value;\n        m.tocApptDate=document.getElementById('nfTOC').value;\n        this.writeMembers();this.render();\n    },\n    hideNotes:function(){\n        // Auto-save\n        var ta=document.getElementById('noteInput');var text=ta?ta.value.trim():'';\n        if(text&&this.notesForId){\n            this.notes.push({id:String(this.nextNid++),memberId:this.notesForId,ts:new Date().toISOString(),note:text});\n            this.writeNotes();ta.value='';this.render();this.toast('Note saved','success');\n        }\n        this.editingNoteId=null;this.notesForId=null;\n        document.getElementById('notesModal').classList.remove('open');\n        document.body.classList.remove('no-scroll');\n        if(this._returnToCalDay){this._returnToCalDay=false;this.showCalDay()}\n    },\n    saveNote:function(){\n        if(!this.notesForId)return;var ta=document.getElementById('noteInput');var text=ta.value.trim();if(!text)return;\n        if(this.editingNoteId){\n            var i=this.notes.findIndex(function(n){return n.id===App.editingNoteId});\n            if(i!==-1){this.notes[i].note=text;this.notes[i].ts=new Date().toISOString()}\n            this.editingNoteId=null;\n        }else{\n            this.notes.push({id:String(this.nextNid++),memberId:this.notesForId,ts:new Date().toISOString(),note:text});\n        }\n        this.writeNotes();ta.value='';document.getElementById('noteBtn').textContent='Add Note';\n        this.renderNotesList();this.render();this.toast('Saved','success');\n    },\n    editNote:function(nid){\n        var n=this.notes.find(function(x){return x.id===nid});if(!n)return;\n        this.editingNoteId=nid;\n        document.getElementById('noteInput').value=n.note;\n        document.getElementById('noteBtn').textContent='Update Note';\n        document.getElementById('noteInput').focus();\n    },\n    deleteNote:function(nid){\n        if(!confirm('Delete this note?'))return;\n        this.notes=this.notes.filter(function(n){return n.id!==nid});\n        this.writeNotes();this.renderNotesList();this.render();\n    },\n    renderNotesList:function(){\n        var list=this.getNotesFor(this.notesForId),self=this;\n        var el=document.getElementById('notesList');\n        if(!list.length){el.innerHTML='<div class=\"notes-empty\">No notes yet.</div>';return}\n        el.innerHTML=list.map(function(n){\n            return '<div class=\"note-card\"><div class=\"note-head\"><span>'+self.fmtTime(n.ts)+'</span><div><button class=\"note-edit\" onclick=\"App.editNote(\\''+n.id+'\\')\" title=\"Edit\">&#9998;</button> <button class=\"note-del\" onclick=\"App.deleteNote(\\''+n.id+'\\')\" title=\"Delete\">&times;</button></div></div><div class=\"note-text-wrap\"><div class=\"note-text\">'+self.esc(n.note)+'</div></div></div>';\n        }).join('');\n    },\n\n    // CALENDAR\n    formatDate:function(d){return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0')},\n    formatDisplay:function(s){if(!s)return'';var p=s.split('-');var d=new Date(+p[0],+p[1]-1,+p[2]);return['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][d.getMonth()]+' '+d.getDate()+', '+d.getFullYear()},\n    calPrev:function(){this.calMonth--;if(this.calMonth<0){this.calMonth=11;this.calYear--}this.calSelectedDate=null;this.renderCalendar()},\n    calNext:function(){this.calMonth++;if(this.calMonth>11){this.calMonth=0;this.calYear++}this.calSelectedDate=null;this.renderCalendar()},\n    calToday:function(){var n=new Date();this.calYear=n.getFullYear();this.calMonth=n.getMonth();this.calSelectedDate=this.formatDate(n);this.renderCalendar()},\n    renderCalendar:function(){\n        var y=this.calYear,mo=this.calMonth;\n        document.getElementById('calTitle').textContent=['January','February','March','April','May','June','July','August','September','October','November','December'][mo]+' '+y;\n        var list=this.filtered();var dateMap={};var self=this;\n        list.forEach(function(m){if(!m.dcDate)return;if(!dateMap[m.dcDate])dateMap[m.dcDate]={count:0,hasUrgent:false,preview:[]};dateMap[m.dcDate].count++;if(m.callType==='Urgent')dateMap[m.dcDate].hasUrgent=true;if(dateMap[m.dcDate].preview.length<3)dateMap[m.dcDate].preview.push(m)});\n        var first=new Date(y,mo,1).getDay(),days=new Date(y,mo+1,0).getDate(),prevDays=new Date(y,mo,0).getDate();\n        var today=this.formatDate(new Date());\n        var html='<div class=\"cal-day-header\">Sun</div><div class=\"cal-day-header\">Mon</div><div class=\"cal-day-header\">Tue</div><div class=\"cal-day-header\">Wed</div><div class=\"cal-day-header\">Thu</div><div class=\"cal-day-header\">Fri</div><div class=\"cal-day-header\">Sat</div>';\n        for(var i=first-1;i>=0;i--)html+='<div class=\"cal-day outside\"><div class=\"cal-day-num\">'+(prevDays-i)+'</div></div>';\n        for(var d=1;d<=days;d++){\n            var ds=y+'-'+String(mo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');\n            var info=dateMap[ds];var cls=['cal-day'];\n            if(ds===today)cls.push('today');if(ds===this.calSelectedDate)cls.push('selected');\n            var inner='';\n            if(info&&info.count){\n                inner='<div class=\"cal-day-badge '+(info.hasUrgent?'urgent':'normal')+'\">'+info.count+'</div>';\n                inner+=info.preview.map(function(m){return '<div class=\"cal-preview\">'+self.esc(m.name).substring(0,18)+'</div>'}).join('');\n                if(info.count>3)inner+='<div class=\"cal-preview-more\">+'+(info.count-3)+' more</div>';\n            }\n            html+='<div class=\"'+cls.join(' ')+'\" onclick=\"App.calClick(\\''+ds+'\\')\"><div class=\"cal-day-num\">'+d+'</div>'+inner+'</div>';\n        }\n        var rem=(7-((first+days)%7))%7;for(var i=1;i<=rem;i++)html+='<div class=\"cal-day outside\"><div class=\"cal-day-num\">'+i+'</div></div>';\n        document.getElementById('calGrid').innerHTML=html;\n    },\n    calClick:function(ds){this.calSelectedDate=ds;this.renderCalendar();this.showCalDay()},\n    showCalDay:function(){\n        if(!this.calSelectedDate)return;\n        var ds=this.calSelectedDate,self=this;\n        var list=this.filtered().filter(function(m){return m.dcDate===ds});\n        if(!list.length){this.toast('No members for '+this.formatDisplay(ds),'info');return}\n        document.getElementById('calDayTitle').innerHTML=list.length+' member'+(list.length!==1?'s':'')+' &mdash; '+this.formatDisplay(ds);\n        document.getElementById('calDayList').innerHTML=list.map(function(m){\n            return '<div class=\"cal-day-card\" onclick=\"App.openFromCal(\\''+m.id+'\\')\">'\n                +'<div class=\"cal-day-card-top\"><div class=\"cal-day-card-name\">'+self.esc(m.name)+'</div><div class=\"cal-day-card-id\">'+self.esc(m.memberId)+'</div></div>'\n                +'<div class=\"cal-day-card-row\">'\n                +(m.callType?'<span>'+self.esc(m.callType)+'</span>':'')\n                +(m.cm?'<span>CM: '+self.esc(m.cm)+'</span>':'')\n                +(m.pcp?'<span>PCP: '+self.esc(m.pcp)+'</span>':'')\n                +'</div></div>';\n        }).join('');\n        document.getElementById('calDayModal').classList.add('open');document.body.classList.add('no-scroll');\n    },\n    hideCalDay:function(){document.getElementById('calDayModal').classList.remove('open');document.body.classList.remove('no-scroll')},\n    openFromCal:function(id){this._returnToCalDay=true;document.getElementById('calDayModal').classList.remove('open');this.showNotes(id)},\n\n    // UTILS\n    esc:function(s){if(s==null)return'';var d=document.createElement('div');d.textContent=String(s);return d.innerHTML},\n    fmtTime:function(iso){try{var d=new Date(iso);return d.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})+' at '+d.toLocaleTimeString('en-US',{hour:'numeric',minute:'2-digit'})}catch(e){return iso}},\n    copy:function(t){navigator.clipboard.writeText(t).then(function(){App.toast('Copied','success')})},\n    toast:function(msg,type){var el=document.createElement('div');el.className='toast toast-'+(type||'info');el.textContent=msg;document.getElementById('toasts').appendChild(el);setTimeout(function(){el.classList.add('out');setTimeout(function(){el.remove()},200)},2500)},\n\n    init:function(){\n        var self=this;\n        document.addEventListener('keydown',function(e){\n            if(e.key==='Escape'){\n                if(document.getElementById('calDayModal').classList.contains('open'))self.hideCalDay();\n                else if(document.getElementById('notesModal').classList.contains('open'))self.hideNotes();\n            }\n        });\n    }\n};\n\nApp.init();\n</script>\n</body>\n</html>\n";
